// Parse RSS XML feeds and extract top articles
const items = $input.all();
const allArticles = [];

for (const item of items) {
  const raw = item.json.data || item.json.body || '';
  const sourceName = item.json.url || 'RSS Feed';

  // Extract items between <item> tags
  const itemMatches = raw.match(/<item[^>]*>([\s\S]*?)<\/item>/gi) || [];

  for (const block of itemMatches.slice(0, 8)) {
    // Title
    const titleMatch = block.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/i);
    const title = titleMatch ? titleMatch[1].trim() : '';

    // Link
    const linkMatch = block.match(/<link>([^<]+)<\/link>/i);
    const link = linkMatch ? linkMatch[1].trim() : '';

    // Description
    const descMatch = block.match(/<description>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/is);
    const desc = descMatch
      ? descMatch[1].replace(/<[^>]+>/g, '').trim().substring(0, 250)
      : '';

    // Pub date
    const dateMatch = block.match(/<pubDate>(.*?)<\/pubDate>/i);
    const pubDate = dateMatch ? dateMatch[1].trim() : '';

    if (title && title.length > 15 && !title.toLowerCase().includes('advertisement')) {
      allArticles.push({ title, link, desc, pubDate, source: sourceName });
    }
  }
}

// Deduplicate by first 40 chars of title
const seen = new Set();
const unique = allArticles.filter(a => {
  const key = a.title.substring(0, 40).toLowerCase();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

console.log(`Parsed ${unique.length} unique articles from ${items.length} feeds`);

return [{ json: { articles: unique.slice(0, 25), count: unique.length, scrapedAt: new Date().toISOString() } }];

