// Extract and parse Claude's ranked idea list
const response = $input.first().json;
const content = response.content?.[0]?.text || '';

if (!content) {
  throw new Error('Claude returned empty response. Check API key and quota.');
}

// Parse numbered list
const lines = content.split('\n').filter(l => l.trim());
const ideas = [];

for (const line of lines) {
  const match = line.match(/^(\d+)\.\s+(.+?)\s+-\s+(.+)$/);
  if (match) {
    ideas.push({
      rank: parseInt(match[1]),
      title: match[2].trim().replace(/^\[|\]$/g, ''),
      why: match[3].trim(),
      generatedAt: new Date().toISOString()
    });
  }
}

if (ideas.length === 0) {
  // Fallback: treat each line as an idea title
  lines.slice(0, 7).forEach((line, i) => {
    ideas.push({ rank: i+1, title: line.replace(/^\d+\.\s*/, '').trim(), why: 'Selected by AI', generatedAt: new Date().toISOString() });
  });
}

console.log(`Extracted ${ideas.length} ranked ideas`);

// Return each idea as a separate item (SplitInBatches will process them one by one)
return ideas.slice(0, 7).map(idea => ({ json: idea }));

