// Parse Claude's multi-format response into structured data
const claudeResponse = $input.first().json;
const ideaData = $('Process Each Idea (Loop)').first().json;

const content = claudeResponse.content?.[0]?.text || '';

if (!content) {
  throw new Error('Claude draft response was empty');
}

// Extract each section
const extractSection = (text, startMarker, endMarker) => {
  const start = text.indexOf(startMarker);
  if (start === -1) return '';
  const contentStart = start + startMarker.length;
  const end = endMarker ? text.indexOf(endMarker, contentStart) : text.length;
  return text.substring(contentStart, end === -1 ? text.length : end).trim();
};

const linkedin = extractSection(content, '---LINKEDIN---', '---INSTAGRAM---');
const instagram = extractSection(content, '---INSTAGRAM---', '---WHATSAPP---');
const whatsapp = extractSection(content, '---WHATSAPP---', null);

// Validate we got content
if (!linkedin || !instagram || !whatsapp) {
  console.warn('Warning: One or more sections missing from Claude response');
  console.log('Raw content:', content.substring(0, 500));
}

// Image prompt for this topic
const imagePrompt = `Professional infographic for Indian CA professionals. Topic: ${ideaData.title}. Style: clean, minimal, dark navy background, purple and white accent colors. Include 3-4 key data points or steps. No stock photos. Modern SaaS aesthetic.`;

console.log(`Parsed drafts for: ${ideaData.title}`);

return [{
  json: {
    idea_title: ideaData.title,
    idea_rank: ideaData.rank,
    idea_why: ideaData.why,
    linkedin_draft: linkedin,
    instagram_draft: instagram,
    whatsapp_draft: whatsapp,
    image_prompt: imagePrompt,
    char_count_linkedin: linkedin.length,
    drafted_at: new Date().toISOString()
  }
}];

